import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";

import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { memoryExplorerPlugin } from "./tools/plugins/memory_explorer";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins
  tools.register(shellPlugin);
  tools.register(rebootPlugin);
  tools.register(memoryExplorerPlugin);

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source: src/index.ts
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Persistence: Managed by run-agent.sh watchdog.
- Connectivity: Full outbound internet access available.

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${recoveryContext ? `*** RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA:
${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}
`;

  await memory.addMessage({ role: "system", content: systemPrompt });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v16 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch(err => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../../utils/config";
import type { ToolPlugin } from "../manager";

interface SessionSummary {
  filename: string;
  timestamp: number;
  messageCount: number;
  hasSystemMessage: boolean;
  lastMessagePreview: string;
}

async function getSessionSummaries(): Promise<SessionSummary[]> {
  const historyDir = config.HISTORY_DIR;
  const files = await fs.readdir(historyDir).catch(() => []);
  const summaries: SessionSummary[] = [];

  for (const file of files) {
    if (!file.endsWith('.json') || !file.startsWith('session_')) continue;

    const filepath = path.join(historyDir, file);
    try {
      const content = await fs.readFile(filepath, 'utf-8');
      const messages = JSON.parse(content);
      const timestamp = parseInt(file.replace('session_', '').replace('.json', ''));

      summaries.push({
        filename: file,
        timestamp,
        messageCount: messages.length,
        hasSystemMessage: messages.length > 0 && messages[0].role === 'system',
        lastMessagePreview: messages.length > 0 
          ? messages[messages.length - 1].content?.substring(0, 100) + '...'
          : 'empty'
      });
    } catch (e) {
      // Skip corrupted files
    }
  }

  return summaries.sort((a, b) => b.timestamp - a.timestamp);
}

export const memoryExplorerPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "explore_history",
      description: "Explore past session history files. Returns a summary of available sessions or detailed content if a specific file is requested.",
      parameters: {
        type: "object",
        properties: {
          action: { 
            type: "string", 
            enum: ["list", "view"],
            description: "'list' to see available sessions, 'view' to see full content of a specific session"
          },
          filename: { 
            type: "string", 
            description: "For 'view' action: the session filename to explore (e.g., 'session_1234567890.json'). Required for 'view'."
          },
          limit: { 
            type: "number", 
            description: "For 'list' action: maximum number of sessions to return (default: 10, max: 50)" 
          }
        },
        required: ["action"],
      },
    },
  },
  execute: async (args: { action: "list" | "view"; filename?: string; limit?: number }) => {
    if (args.action === "list") {
      const limit = Math.min(args.limit ?? 10, 50);
      const summaries = await getSessionSummaries();
      const recent = summaries.slice(0, limit);

      if (recent.length === 0) {
        return "No session history files found.";
      }

      let output = `📚 Session History (${recent.length} of ${summaries.length} total):\n\n`;
      for (const s of recent) {
        const date = new Date(s.timestamp).toISOString();
        output += `[${date}] ${s.filename}\n`;
        output += `   Messages: ${s.messageCount} | System: ${s.hasSystemMessage ? '✓' : '✗'}\n`;
        output += `   Preview: ${s.lastMessagePreview?.substring(0, 80)}...\n\n`;
      }

      return output;
    }

    if (args.action === "view") {
      if (!args.filename) {
        return "Error: 'filename' is required for 'view' action.";
      }

      const filepath = path.join(config.HISTORY_DIR, args.filename);

      // Security: ensure file is within history dir
      const resolvedPath = path.resolve(filepath);
      const resolvedHistoryDir = path.resolve(config.HISTORY_DIR);
      if (!resolvedPath.startsWith(resolvedHistoryDir)) {
        return "Error: Invalid filename - path traversal detected.";
      }

      try {
        const content = await fs.readFile(filepath, 'utf-8');
        const messages = JSON.parse(content);

        let output = `📖 Session: ${args.filename}\n`;
        output += `Messages: ${messages.length}\n`;
        output = output.padEnd(60, '=') + '\n\n';

        // Show first 20 messages with truncation notice if more exist
        const displayCount = Math.min(messages.length, 20);
        for (let i = 0; i < displayCount; i++) {
          const m = messages[i];
          const preview = m.content?.substring(0, 200) + (m.content?.length > 200 ? '...' : '');
          output += `[${i}] ${m.role.toUpperCase()}: ${preview}\n\n`;
        }

        if (messages.length > displayCount) {
          output += `... and ${messages.length - displayCount} more messages ...\n`;
        }

        return output;
      } catch (e: any) {
        return `Error reading session: ${e.message}`;
      }
    }

    return "Error: Unknown action. Use 'list' or 'view'.";
  }
};

import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../utils/config";

export interface Message {
  role: "system" | "user" | "assistant" | "tool";
  content?: string | null;
  reasoning_content?: string | null;
  tool_calls?: any[];
  tool_call_id?: string;
  name?: string;
}

export class MemoryManager {
  private messages: Message[] = [];
  private sessionFile: string;
  private currentTokens: number = 0;
  private dirtyCount: number = 0;
  private readonly SAVE_INTERVAL = 5;

  constructor() {
    const timestamp = Date.now();
    this.sessionFile = path.join(config.HISTORY_DIR, `session_${timestamp}.json`);
  }

  getMessages(): Message[] {
    return this.messages;
  }

  async addMessage(msg: Message) {
    this.messages.push(msg);
    this.currentTokens += this.estimateTokens(JSON.stringify(msg));
    this.dirtyCount++;

    if (this.currentTokens > config.MAX_CONTEXT_TOKENS) {
      await this.save(); // Pruning required
      this.dirtyCount = 0;
    } else if (this.dirtyCount >= this.SAVE_INTERVAL) {
      await this.save();
      this.dirtyCount = 0;
    }
  }

  /**
   * Surgical Memory Rewind: Removes the last assistant message and everything after it.
   */
  async rewind() {
    for (let i = this.messages.length - 1; i >= 0; i--) {
      const msg = this.messages[i];
      if (msg && msg.role === "assistant") {
        console.log(`[MEMORY] Rewinding: Removing corrupted assistant message at index ${i}`);
        this.messages.splice(i);
        break;
      }
    }
    // Re-calculate token count after rewind
    this.currentTokens = this.messages.reduce((sum, m) => sum + this.estimateTokens(JSON.stringify(m)), 0);
    await this.save();
  }

  private estimateTokens(text: string): number {
    return Math.ceil(text.length / 4);
  }

  async save() {
    if (this.messages.length === 0) return;

    const systemMessage = this.messages[0]!;
    let currentTokens = this.estimateTokens(JSON.stringify(systemMessage));
    const historyToKeep: Message[] = [];

    // Accumulate from end until limit
    for (let i = this.messages.length - 1; i > 0; i--) {
      const msg = this.messages[i];
      if (!msg) continue;
      const msgTokens = this.estimateTokens(JSON.stringify(msg));
      if (currentTokens + msgTokens > config.MAX_CONTEXT_TOKENS) break;
      historyToKeep.unshift(msg);
      currentTokens += msgTokens;
    }

    // C1: Repair pruning boundary to prevent orphaned tool messages
    while (historyToKeep.length > 0 && historyToKeep[0]!.role === "tool") {
      console.log("[MEMORY] Pruning boundary repair: dropping orphaned tool message");
      historyToKeep.shift();
    }

    const pruned = [systemMessage, ...historyToKeep];
    this.messages = pruned; // Update in-memory state
    this.currentTokens = currentTokens; // Update tracked token count
    await fs.writeFile(this.sessionFile, JSON.stringify(pruned, null, 2));
  }

  getSessionFile(): string {
    return this.sessionFile;
  }
}

export interface ToolPlugin {
  definition: {
    type: "function";
    function: {
      name: string;
      description: string;
      parameters: object;
    };
  };
  execute: (args: any) => Promise<string> | string;
}

export class PluginManager {
  private plugins: Map<string, ToolPlugin> = new Map();

  register(plugin: ToolPlugin) {
    this.plugins.set(plugin.definition.function.name, plugin);
  }

  getDefinitions() {
    return Array.from(this.plugins.values()).map(p => p.definition);
  }

  async execute(name: string, args: any): Promise<string> {
    const plugin = this.plugins.get(name);
    if (!plugin) {
      return `Error: Tool '${name}' not found.`;
    }
    try {
      return await plugin.execute(args);
    } catch (e: any) {
      return `Error executing tool '${name}': ${e.message}`;
    }
  }
}

